sql:
SELECT block_owner 
FROM address_blocks 
WHERE number_of_addresses > 1000;

SELECT COUNT(*)
FROM address_assignments
WHERE assignment_type = 'static';

SELECT address_assignments.address, devices.device_name
FROM address_assignments
JOIN devices ON address_assignments.device_id = devices.device_id;

SELECT scope, COUNT(*) AS 'Number of Address Blocks'
FROM address_blocks
GROUP BY scope;

SELECT COUNT(aa.assignment_id) AS total_assigned_addresses
FROM address_assignments aa
WHERE aa.assigned_by_user_id = 1;

SELECT AVG(device_count) AS average_devices_per_user
FROM (
  SELECT COUNT(device_id) AS device_count
  FROM devices
  GROUP BY device_owner
);

SELECT COUNT(*)
FROM address_blocks
WHERE status = 'active';

SELECT d.device_name, aa.address
FROM devices d
INNER JOIN address_assignments aa ON d.device_id = aa.device_id;

SELECT block_id, address_block_cidr, number_of_addresses, block_type
FROM address_blocks
WHERE block_owner = 'Network Team';

SELECT assigned_by_user_id
FROM address_assignments
WHERE assigned_at = (
    SELECT MAX(assigned_at)
    FROM address_assignments
);

SELECT address 
FROM address_assignments 
WHERE address = '::1';
